## Comprehensive Transformers.js Multimodal Pipeline Analysis

I've thoroughly explored the Transformers.js codebase and analyzed the multimodal pipeline patterns. Here's my complete findings:

### 1. **Multimodal Pipelines Using Image Processor + Tokenizer**

The following pipelines use **both** an image processor AND a tokenizer:

1. **ImageToTextPipeline** - Generates text captions from images
2. **ZeroShotImageClassificationPipeline** - Classifies images with text labels
3. **ZeroShotObjectDetectionPipeline** - Detects objects with text descriptions
4. **DocumentQuestionAnsweringPipeline** - Answers questions about document images

---

### 2. **Full Pipeline Implementations**

#### **ImageToTextPipeline** (`/src/pipelines.js` lines 1975-2005)
```javascript
export class ImageToTextPipeline extends Pipeline {
    constructor(options) {
        super(options);
    }

    async _call(images, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        const { pixel_values } = await this.processor(preparedImages);

        const toReturn = [];
        for (const batch of pixel_values) {
            batch.dims = [1, ...batch.dims]
            const output = await this.model.generate({ inputs: batch, ...generate_kwargs });
            const decoded = this.tokenizer.batch_decode(output, {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }))
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

#### **ZeroShotImageClassificationPipeline** (`/src/pipelines.js` lines 2389-2444)
```javascript
export class ZeroShotImageClassificationPipeline extends Pipeline {
    constructor(options) {
        super(options);
    }

    async _call(images, candidate_labels, {
        hypothesis_template = "This is a photo of {}"
    } = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Insert label into hypothesis template
        const texts = candidate_labels.map(
            x => hypothesis_template.replace('{}', x)
        );

        // Run tokenization
        const text_inputs = this.tokenizer(texts, {
            padding: this.model.config.model_type === 'siglip' ? 'max_length' : true,
            truncation: true,
        });

        // Run processor
        const { pixel_values } = await this.processor(preparedImages);

        // Run model with both text and pixel inputs
        const output = await this.model({ ...text_inputs, pixel_values });

        const function_to_apply =
            this.model.config.model_type === 'siglip'
                ? batch => batch.sigmoid().data
                : batch => softmax(batch.data);

        // Compare each image with each candidate label
        const toReturn = [];
        for (const batch of output.logits_per_image) {
            const probs = function_to_apply(batch);
            const result = [...probs].map((x, i) => ({
                score: x,
                label: candidate_labels[i]
            }));
            result.sort((a, b) => b.score - a.score);
            toReturn.push(result);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

#### **ZeroShotObjectDetectionPipeline** (`/src/pipelines.js` lines 2624-2702)
```javascript
export class ZeroShotObjectDetectionPipeline extends Pipeline {
    constructor(options) {
        super(options);
    }

    async _call(images, candidate_labels, {
        threshold = 0.1,
        top_k = null,
        percentage = false,
    } = {}) {

        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Run tokenization
        const text_inputs = this.tokenizer(candidate_labels, {
            padding: true,
            truncation: true,
        });

        // Run processor
        const model_inputs = await this.processor(preparedImages);

        const toReturn = [];
        for (let i = 0; i < preparedImages.length; ++i) {
            const image = preparedImages[i];
            const imageSize = percentage ? null : [[image.height, image.width]];
            const pixel_values = model_inputs.pixel_values[i].unsqueeze_(0);

            // Run model with both text and pixel inputs
            const output = await this.model({ ...text_inputs, pixel_values });

            let result;
            if ('post_process_grounded_object_detection' in this.processor) {
                const processed = this.processor.post_process_grounded_object_detection(
                    output,
                    text_inputs.input_ids,
                    {
                        box_threshold: threshold,
                        text_threshold: threshold,
                        target_sizes: imageSize,
                    },
                )[0];
                result = processed.boxes.map((box, i) => ({
                    score: processed.scores[i],
                    label: processed.labels[i],
                    box: get_bounding_box(box, !percentage),
                }))
            } else {
                const processed = this.processor.image_processor.post_process_object_detection(output, threshold, imageSize, true)[0];
                result = processed.boxes.map((box, i) => ({
                    score: processed.scores[i],
                    label: candidate_labels[processed.classes[i]],
                    box: get_bounding_box(box, !percentage),
                }))
            }
            result.sort((a, b) => b.score - a.score);

            if (top_k !== null) {
                result = result.slice(0, top_k);
            }
            toReturn.push(result)
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

#### **DocumentQuestionAnsweringPipeline** (`/src/pipelines.js` lines 2732-2779)
